'use strict';

var invalid = [];

// Empty line between consecutive requires:
var test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );'
	].join( '\n' )
};
invalid.push( test );

// Multiple empty lines between requires:
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'',
		'',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );'
	].join( '\n' )
};
invalid.push( test );

// Empty line in middle of multiple requires:
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );',
		'',
		'var abs = require( \'./../lib\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );',
		'var abs = require( \'./../lib\' );'
	].join( '\n' )
};
invalid.push( test );

// Empty lines in FIXTURES section (no section header between):
test = {
	'code': [
		'\'use strict\';',
		'',
		'// FIXTURES //',
		'',
		'var data = require( \'./fixtures/data.json\' );',
		'',
		'var expected = require( \'./fixtures/expected.json\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'// FIXTURES //',
		'',
		'var data = require( \'./fixtures/data.json\' );',
		'var expected = require( \'./fixtures/expected.json\' );'
	].join( '\n' )
};
invalid.push( test );

// Multiple consecutive errors:
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var a = require( \'a\' );',
		'',
		'var b = require( \'b\' );',
		'',
		'var c = require( \'c\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		},
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var a = require( \'a\' );',
		'var b = require( \'b\' );',
		'var c = require( \'c\' );'
	].join( '\n' )
};
invalid.push( test );

// Empty line before a regular comment (not a section header):
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var foo = require( \'foo\' );',
		'',
		'// A regular comment',
		'var bar = require( \'bar\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var foo = require( \'foo\' );',
		'// A regular comment',
		'var bar = require( \'bar\' );'
	].join( '\n' )
};
invalid.push( test );

// Empty line with require using property access:
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var isString = require( \'@stdlib/assert/is-string\' ).isPrimitive;',
		'',
		'var format = require( \'@stdlib/string/format\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var isString = require( \'@stdlib/assert/is-string\' ).isPrimitive;',
		'var format = require( \'@stdlib/string/format\' );'
	].join( '\n' )
};
invalid.push( test );

// Empty line between requires separated by non-require statement:
test = {
	'code': [
		'\'use strict\';',
		'',
		'var foo = require( \'foo\' );',
		'var x = 1;',
		'',
		'var bar = require( \'bar\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'var foo = require( \'foo\' );',
		'var x = 1;',
		'var bar = require( \'bar\' );'
	].join( '\n' )
};
invalid.push( test );

// Empty line between multi-line require statements:
test = {
	'code': [
		'\'use strict\';',
		'',
		'var foo = require(',
		'    \'some/very/long/path/to/module\'',
		');',
		'',
		'var bar = require( \'bar\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'var foo = require(',
		'    \'some/very/long/path/to/module\'',
		');',
		'var bar = require( \'bar\' );'
	].join( '\n' )
};
invalid.push( test );

// Empty line after multi-line require followed by another multi-line require:
test = {
	'code': [
		'\'use strict\';',
		'',
		'var foo = require(',
		'    \'path/one\'',
		');',
		'',
		'var bar = require(',
		'    \'path/two\'',
		');'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'var foo = require(',
		'    \'path/one\'',
		');',
		'var bar = require(',
		'    \'path/two\'',
		');'
	].join( '\n' )
};
invalid.push( test );

// Multiple non-require statements between requires with empty lines:
test = {
	'code': [
		'\'use strict\';',
		'',
		'var foo = require( \'foo\' );',
		'var x = 1;',
		'',
		'var y = 2;',
		'var z = x + y;',
		'',
		'var bar = require( \'bar\' );'
	].join( '\n' ),
	'errors': [
		{
			'message': 'Unexpected empty line between require statements.',
			'type': null
		}
	],
	'output': [
		'\'use strict\';',
		'',
		'var foo = require( \'foo\' );',
		'var x = 1;',
		'var y = 2;',
		'var z = x + y;',
		'var bar = require( \'bar\' );'
	].join( '\n' )
};
invalid.push( test );


// EXPORTS //

module.exports = invalid;
